def least_frequent_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    min_count = min(word_count.values())
    least_words = [word for word, count in word_count.items() if count == min_count]

    return sorted(least_words)[0]
